const error = $input.first().json;

const workflowName = error.workflow?.name || 'Desconocido';
const nodeName = error.execution?.lastNodeExecuted || 'Desconocido';
const errorMessage = error.execution?.error?.message || 'Error desconocido';
const number = error.execution?.data?.resultData?.runData?.['Global Variables']?.[0]?.data?.main?.[0]?.[0]?.json?.number || null;

return [{ json: { workflowName, nodeName, errorMessage, number } }];

// Funciona tanto desde WhatsApp (subflow) como desde el chat trigger
const input = $input.first().json;

// Desde WhatsApp llega 'numero', desde chat llega 'sessionId' o 'chatInput'
const sessionId = input.numero || input.sessionId || input.chatInput || 'unknown';

// El mensaje puede venir como 'mensaje' (WhatsApp) o 'chatInput' (chat)
const chatInput = input.mensaje || input.chatInput || '';

// El contexto refinado viene del toDeploy (solo en modo WhatsApp)
const contexto = input.contexto || '';

const key = 'activeAgent_' + sessionId;
const stored = $getWorkflowStaticData('global');
const activeAgent = stored[key] || null;

return [{ json: { chatInput, sessionId, activeAgent, contexto, numero: sessionId } }];
